joi_block.script:
hold_ticks := 0
if ((#MotionSensor #LivingRoom).motionSensor_motion == false) {
hold_ticks = hold_ticks + 1
    if (hold_ticks >= 300) {
(#Plug #Switch #LivingRoom #Strip).switch_off()
        break
}
}
else {
hold_ticks = 0
}

